SELECT COUNT(1)
FROM posts

    status = 'published'

        AND author IN (
        SELECT u.username
        FROM user_follow uf
                 INNER JOIN users u ON uf.target_user_id = u.id
        WHERE uf.user_id = #{requesterUserId}
        )


        AND (

                (
                title LIKE CONCAT('%', #{term}, '%')
                OR content LIKE CONCAT('%', #{term}, '%')
                OR author LIKE CONCAT('%', #{term}, '%')
                OR tags_json LIKE CONCAT('%', #{term}, '%')
                )

        )


        AND author LIKE CONCAT('%', #{author}, '%')


        AND tags_json LIKE CONCAT('%', #{tag}, '%')


        AND board_id = #{boardId}


        AND format = #{format}


        AND created_at >= #{dateFrom}


        AND created_at <= #{dateTo}

